import kotlinx.coroutines.*

fun main() = runBlocking {
    println("Main starts: ${Thread.currentThread().name}")

    val job = launch {
        println("Coroutine starts: ${Thread.currentThread().name}")
        delay(1000)
        println("Coroutine ends")
    }

    println("Waiting for coroutine...")
    job.join()
    println("Main ends")
}
